// Fetch weather data for a lat/lon position — delegates coord validation to shared helper.
// Enriches the response with sea safety status (current + hourly) for the global indicator.
async function getWeather(c) {
  return functions.call('withValidatedCoords', c, async (lat, lon) => {
    const result = await functions.call('fetchWeather', lat, lon);

    // Map Result to HTTP response — success returns data, failure returns 500
    if (!result.ok) {
      return c.json({ error: true, message: result.error.message }, 500);
    }

    const weatherData = result.data;

    // Compute overall sea safety for current conditions
    const seaStatus = functions.call('computeSeaStatus', weatherData.current);

    // Compute sea safety for each hourly forecast entry so timeline can show it
    const hourlySeaStatus = weatherData.hourly.map((hour) =>
      functions.call('computeSeaStatus', hour)
    );

    // Attach sea status fields alongside existing weather data
    return c.json({
      ...weatherData,
      seaStatus,
      hourlySeaStatus
    });
  }, 'Failed to fetch weather data');
}
